import{_ as s,o as a,c as e,a6 as t}from"./chunks/framework.DtxWasON.js";const c=JSON.parse('{"title":"WRKChain Example","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/examples/wrkchain.md","filePath":"mainchain/examples/wrkchain.md"}'),n={name:"mainchain/examples/wrkchain.md"};function h(l,i,o,r,k,p){return a(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="wrkchain-example" tabindex="-1">WRKChain Example <a class="header-anchor" href="#wrkchain-example" aria-label="Permalink to &quot;WRKChain Example&quot;">​</a></h1><p>This document will guide you though registering a new WRKChain and submitting hashes via a manual process. Although hash submission is usually automated with the WRKOracle software, this guide will help you understand the process, and allow for testing.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Whenever you use <code>und</code> to send Txs or query the chain ensure you pass the correct data to the <code>--chain-id</code> and if necessary <code>--node=</code> flags so that you connect to the correct network!</p></div><div class="tip custom-block"><p class="custom-block-title">Note</p><p>It is <em>HIGHLY</em> recommended that you only undertake this guide on either <a href="./local-devnet.html">DevNet</a> or TestNet first.</p></div><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#registering-your-wrkchain">Registering your WRKChain</a></li><li><a href="#filter-wrkchain-metadata">Filter WRKChain metadata</a></li><li><a href="#recording-hashes">Recording Hashes</a></li><li><a href="#querying-a-wrkchain-on-mainchain">Querying a WRKChain on Mainchain</a></li></ul></nav><h2 id="registering-your-wrkchain" tabindex="-1">Registering your WRKChain <a class="header-anchor" href="#registering-your-wrkchain" aria-label="Permalink to &quot;Registering your WRKChain&quot;">​</a></h2><p>Registration is required so that the WRKChain has an identifier on Mainchain. Registration incurs a one-time fee.</p><p>The following <code>und</code> command can be used to register your WRKChain, and assumes you have a local full node running, connected to either DevNet or TestNet:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> register</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --moniker=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[YOUR_MONIKER]&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --genesis=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[GENESIS_BLOCK_HASH]&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[WRKCHAIN NAME]&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --base=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[WRKCHAIN_TYPE]&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [from_account] --chain-id [chain_id] --gas</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">auto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --gas-adjustment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1.5</span></span></code></pre></div><ul><li><code>[YOUR_MONIKER]</code> - any alphanumeric identifier you want to give your WRKChain, e.g. wrkchain1</li><li><code>[GENESIS_BLOCK_HASH]</code> - the hash value for your genesis block. The <code>--genesis</code> flag is optional. The hash can be obtained by running your genesis through a sha256 generator, for example.</li><li><code>[WRKCHAIN NAME]</code> - a name for your WRKChain, e.g. My First WRKChain. Optional</li><li><code>[from_account]</code> - your local account identifier (see <a href="./accounts-wallets.html">Accounts and Wallets</a>). This will be used as the WRKChain Owner. <strong>Only the owner will be able to submit block hashes, so it is important to keep this account safe!</strong></li><li><code>[chain_id]</code> - the ID of the chain to run the transaction on</li><li><code>[WRKCHAIN_TYPE]</code> - the type of WRKChain. Currently supported by WRKOracle are WRKChains built using <code>cosmos</code>, <code>eos</code> , <code>geth</code>, <code>neo</code>, <code>stellar</code>, <code>tendermint</code>.</li></ul><p>For example, we have a local account and key set up called &quot;testwrk&quot;, and want to register a new WRKChain, with the moniker &quot;wrkchain1&quot; called &quot;WRKChain Example 1&quot;:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> register</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --moniker=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wrkchain1&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --genesis=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;78521D6EFBEDF6D7EE9C73EDD3443B8021DADBE06ECE81F639B6EC57D8E3F3EA&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WRKChain Example 1&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --base=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tendermint&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> testwrk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FUND-DevNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gas=auto</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gas-adjustment=1.25</span></span></code></pre></div><p>Once broadcast, you will receive confirmation with the TX Hash, which can be used to query the Tx.</p><p>Your WRKCHain&#39;s on-chain ID will be embedded in the Tx query result. Alternatively, you can run a search query to get your WRKChain&#39;s details, for example:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --moniker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FUND-DevNet-2</span></span></code></pre></div><p>will return a result similar to:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;wrkchain_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;moniker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wrkchain1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;WRKChain Example 1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;genesis&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;78521D6EFBEDF6D7EE9C73EDD3443B8021DADBE06ECE81F639B6EC57D8E3F3EA&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tendermint&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;lastblock&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;num_blocks&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;reg_time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1585752449&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;owner&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;und1x8pl6wzqf9atkm77ymc5vn5dnpl5xytmn200xy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>The <code>wrkchain_id</code> value is what is required to submit hashes, and find your WRKChain&#39;s submitted block hashes.</p><p>The <code>lastblock</code> tells us for which block number hashes were last submitted for the WRKChain, and <code>num_blocks</code> the number of block hashes the WRKChain has submitted in total. Finally, <code>reg_time</code> is a UNIX timestamp for when the WRKChain was registered on Mainchain.</p><blockquote><p><strong>Important</strong>: Only the <code>owner</code> - i.e. the account used to register the WRKChain - will be able to submit block hashes.</p></blockquote><h2 id="filter-wrkchain-metadata" tabindex="-1">Filter WRKChain metadata <a class="header-anchor" href="#filter-wrkchain-metadata" aria-label="Permalink to &quot;Filter WRKChain metadata&quot;">​</a></h2><p>WRKChain metadata can be searched for on Mainchain:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>und query wrkchain search --moniker wrkchain1</span></span>
<span class="line"><span>und query wrkchain search --owner und1chknpc8nf2tmj5582vhlvphnjyekc9ypspx5ay</span></span>
<span class="line"><span>und query wrkchain search --page=2 --limit=100</span></span></code></pre></div><h2 id="recording-hashes" tabindex="-1">Recording Hashes <a class="header-anchor" href="#recording-hashes" aria-label="Permalink to &quot;Recording Hashes&quot;">​</a></h2><p>Once successfully registered, you will be able to submit block hashes however frequently suits your needs. To simulate how the WRKOracle works, we can run the following command to submit hashes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> record</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --wc_height=[BLOCK_HEIGHT]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --block_hash=[BLOCK_HASH]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --parent_hash=[PARENT_HASH]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hash1=[HASH1]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hash2=[HASH2]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --hash3=[HASH3]</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [account_name] --chain-id [chain_id] --gas</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">auto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> --gas-adjustment</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1.5</span></span></code></pre></div><ul><li><code>[BLOCK_HEIGHT]</code> - the height/number of the WRKChain block you are submitting hashes for</li><li><code>[BLOCK_HASH]</code> - the main block hash</li><li><code>[PARENT_HASH]</code> - the main block&#39;s parent block hash (optional)</li><li><code>[HASH1]</code> - an optional, arbitrary hash. This can be, for example, the Tx Merkle root hash</li><li><code>[HASH2]</code> - an optional, arbitrary hash. This can be, for example, the Tx Merkle root hash</li><li><code>[HASH3]</code> - an optional, arbitrary hash. This can be, for example, the Tx Merkle root hash</li><li><code>[from_account]</code> - your local account identifier (see <a href="./accounts-wallets.html">Accounts and Wallets</a>). This <strong>must</strong> be the same as the <strong>owner</strong> used to register the WRKChain.</li><li><code>[chain_id]</code> - the ID of the chain to run the transaction on</li></ul><p>For example, if we just want to submit the block hash for block number 123, we can run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> record</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --wc_height=123</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --block_hash=1BB457C575E72D7401C809B66290FAC56347223912F2484BA7E881D42495CD0F</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> testwrk</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FUND-DevNet-2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gas=auto</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --gas-adjustment=1.5</span></span></code></pre></div><h2 id="querying-a-wrkchain-on-mainchain" tabindex="-1">Querying a WRKChain on Mainchain <a class="header-anchor" href="#querying-a-wrkchain-on-mainchain" aria-label="Permalink to &quot;Querying a WRKChain on Mainchain&quot;">​</a></h2><p>To retrieve a particular hash submitted for a WRKChain, we can run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wrkchain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> block</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [WRKCHAIN_ID] [HEIGHT]</span></span></code></pre></div><ul><li><code>[WRKCHAIN_ID]</code> - the numeric ID for the WRKChain</li><li><code>[HEIGHT]</code> - the block number we wish to retrieve</li></ul><p>If <code>[HEIGHT]</code> has been submitted for <code>[WRKCHAIN_ID]</code>, the data will be returned in a JSON object, If not, the returned object will contain empty values, meaning the WRKChain has not submitted a value for this block height.</p>`,35)])])}const u=s(n,[["render",h]]);export{c as __pageData,u as default};
